class="rounded-xl border px-3 py-2 text-sm font-bold">Planbar</button><button type="button" @click="draft.priority=3" :class="draft.priority===3?'bg-amber-500 border-amber-400 text-gray-950':'border-gray-700 text-gray-300'" class="rounded-xl border px-3 py-2 text-sm font-bold">Normal</button><button type="button" @click="draft.priority=5" :class="draft.priority===5?'bg-red-600 border-red-500 text-white':'border-gray-700 text-gray-300'" class="rounded-xl border px-3 py-2 text-sm font-bold">Dringend</button></div></div><div><div class="flex items-center justify-between"><span class="text-sm font-bold">Zeitfenster</span><button type="button" @click="draft.window_start='';draft.window_end=''" class="text-xs text-gray-400 hover:text-white">Kein Zeitfenster</button></div><div class="grid grid-cols-2 gap-3 mt-2"><label class="text-xs text-gray-400">Frühestens<input x-model="draft.window_start" type="time" class="sck-input rounded-xl w-full mt-1"></label><label class="text-xs text-gray-400">Spätestens<input x-model="draft.window_end" type="time" class="sck-input rounded-xl w-full mt-1"></label></div></div></div><details class="md:col-span-2 rounded-2xl border border-gray-800 bg-gray-950/30 group"><summary class="cursor-pointer list-none px-4 py-3 flex items-center justify-between font-bold"><span><i class="fa-solid fa-sliders mr-2 text-purple-400"></i>Zusätzliche Hinweise</span><i class="fa-solid fa-chevron-down text-gray-500 transition-transform group-open:rotate-180"></i></summary><div class="border-t border-gray-800 p-4 grid md:grid-cols-2 gap-4"><label class="text-sm font-bold">Kontaktperson<input x-model="draft.contact_name" class="sck-input rounded-xl w-full mt-1"></label><label class="text-sm font-bold">Kontakt-Telefon<input x-model="draft.contact_phone" class="sck-input rounded-xl w-full mt-1"></label><label class="text-sm font-bold">Zugang<textarea x-model="draft.access_notes" class="sck-input rounded-xl w-full mt-1" rows="3" placeholder="Schlüssel, Anmeldung, Zuga