@push('styles')<style>[data-edit-draft]{align-items:center;color:#6b7280!important;display:inline-flex;font-size:0!important;height:1rem;justify-content:center;opacity:.6;padding:0!important;transition:color .15s ease,opacity .15s ease;width:1rem}[data-edit-draft] i{font-size:.65rem!important;margin:0!important}[data-edit-draft]:hover,[data-edit-draft]:focus-visible{color:#c084fc!important;opacity:1}</style>@endpush
@push('scripts')<script>function routeDraft(drafts,customers){const blank=()=>({title:'',address:'',customer_id:'',type:'service',service_minutes:30,priority:3,window_start:'',window_end:'',contact_name:'',contact_phone:'',access_notes:'',parking_notes:'',notes:''});return{drafts,customers,templateSearch:'',draftOpen:false,savingDraft:false,draftError:'',editingDraftId:null,draft:blank(),init(){this.$nextTick(()=>this.attachDraftEditors())},templateMatches(value){return value.toLocaleLowerCase().includes(this.templateSearch.trim().toLocaleLowerCase())},hasMatchingTemplate(){return [...document.querySelectorAll('[name="template_ids[]"]')].some(input=>input.closest('label').style.display!=='none')},preloadCustomerAddress(){const customer=this.customers.find(customer=>String(customer.id)===String(this.draft.customer_id));if(!customer)return;this.draft.address=customer.address||'';this.draft.contact_name=customer.name||'';this.draft.contact_phone=customer.phone||''},attachDraftEditors(){this.$root.querySelectorAll('[name="draft_stop_ids[]"]').forEach(input=>{const card=input.closest('label');if(card.querySelector('[data-edit-draft]'))return;const button=document.createElement('button');button.type='button';button.dataset.editDraft='';button.className='ml-auto self-center text-xs font-bold text-purple-300 hover:text-white';button.innerHTML='<i class="fa-solid fa-pen mr-1"></i>Bearbeiten';button.onclick=event=>{event.preventDefault();event.stopPropagation();this.editDraft(input.value)};card.appendChild(button)})},editDraft(id){const stop=this.drafts.find(item=>String(item.id)===String(id));if(!stop)return;this.editingDraftId=stop.id;this.draft={...blank(),...stop};this.draftOpen=true},async addDraft(){this.savingDraft=true;this.draftError='';try{const editing=!!this.editingDraftId;const url=editing?@js(route('sck.routen.draft-stopps.update',['draftId'=>'__draft__'])).replace('__draft__',this.editingDraftId):@js(route('sck.routen.draft-stopps.store'));let r=editing?await axios.put(url,this.draft):await axios.post(url,this.draft);if(editing){this.drafts=this.drafts.map(stop=>String(stop.id)===String(this.editingDraftId)?r.data.stop:stop)}else this.drafts.push(r.data.stop);this.draftOpen=false;this.editingDraftId=null;this.draft=blank();this.$nextTick(()=>this.attachDraftEditors())}catch(e){this.draftError=e.response?.data?.message||'Stopp konnte nicht gespeichert werden.'}finally{this.savingDraft=false}}}}</script>@endpush
